sql:
SELECT school_name
FROM law_schools
WHERE founding_year > 1960 AND accreditation_status = 'accredited';

SELECT school_name, ranking 
FROM law_schools 
ORDER BY ranking DESC;

external_knowledge:
- "shadows" metaphorically refers to rejected applicants;
- "crossed the threshold" metaphorically means they applied to the law schools;
- "turning away" indicates the applications were rejected;
- "brightness of their undergraduate GPAs" is a metaphorical expression for the applicants' academic performance in their undergraduate studies.

sql:
SELECT DISTINCT applicants.name
FROM applicants
JOIN applications ON applicants.applicant_id = applications.applicant_id;

SELECT a.email
FROM applicants a
INNER JOIN users u ON a.applicant_id = u.user_id;
